    "answer": "参考代码：\nimport json\n\n# 模拟爬虫数据\ndata = {\n    'status': 'success',\n    'code': 200,\n    'data': {\n        'books': [\n            {\n                'id': 1,\n                'name': 'Python爬虫入门',\n                'author': '张三',\n                'price': 59.00,\n                'tags': ['Python', '爬虫', '入门'],\n                'in_stock': True\n            },\n            {\n                'id': 2,\n                'name': '机器学习实战',\n                'author': '李四',\n                'price': 79.00,\n                'tags': ['机器学习', 'AI', '实战'],\n                'in_stock': True\n            }\n        ],\n        'total': 2,\n        'page': 1\n    },\n    'message': '获取成功'\n}\n\n# 1. 序列化：Python对象 → JSON字符串\nprint('1. JSON序列化（dumps）：')\njson_str = json.dumps(data, ensure_ascii=False, indent=2)\nprint(json_str)\nprint()\n\n# 2. 反序列化：JSON字符串 → Python对象\nprint('2. JSON反序列化（loads）：')\njson_string = '{\"name\": \"数据分析\", \"price\": 69, \"tags\": [\"Python\", \"数据分析\"]}'\nparsed_data = json.loads(json_string)\nprint(f'解析后类型：{type(parsed_data)}')\nprint(f'书名：{parsed_data[\"name\"]}')\nprint(f'价格：{parsed_data[\"price\"]}')\nprint(f'标签：{parsed_data[\"tags\"]}')\nprint()\n\n# 3. 写入JSON文件（dump）\nprint('3. 写入JSON文件（dump）...')\nwith open('books.json', 'w', encoding='utf-8') as f:\n    json.dump(data, f, ensure_ascii=False, indent=2)\nprint('books.json写入成功！')\nprint()\n\n# 4. 读取JSON文件（load）\nprint('4. 读取JSON文件（load）：')\nwith open('books.json', 'r', encoding='utf-8') as f:\n    loaded_data = json.load(f)\n\nprint(f'状态：{loaded_data[\"status\"]}')\nprint(f'书本数量：{loaded_data[\"data\"][\"total\"]}')\nprint(f'第一本书：{loaded_data[\"data\"][\"books\"][0][\"name\"]}')\nprint()\n\n# 5. 常用参数说明\nprint('5. json.dumps常用参数：')\nprint('- ensure_ascii=False：支持中文显示')\nprint('- indent=2：缩进格式化，便于阅读')\nprint('- sort_keys=True：按键名排序')\n\n预期输出：\n1. JSON序列化（dumps）：\n{\n  \"status\": \"success\",\n  \"code\": 200,\n  \"data\": {\n    \"books\": [\n      {\n        \"id\": 1,\n        \"name\": \"Python爬虫入门\",\n        ...\n      }\n    ]\n  }\n}\n\n2. JSON反序列化（loads）：\n解析后类型：<class 'dict'>\n书名：数据分析\n价格：69\n标签：['Python', '数据分析']\n\n3. 写入JSON文件（dump）...\nbooks.json写入成功！\n\n4. 读取JSON文件（load）：\n状态：success\n书本数量：2\n第一本书：Python爬虫入门\n\n5. json.dumps常用参数：\n- ensure_ascii=False：支持中文显示\n- indent=2：缩进格式化，便于阅读\n- sort_keys=True：按键名排序",
