    "answer": "参考代码（pipelines.py）：\n\nimport pymongo\nfrom itemadapter import ItemAdapter\n\nclass MongoDBPipeline:\n    '''\n    将数据存储到MongoDB的Pipeline\n    支持分布式环境，所有节点写入同一个数据库\n    '''\n    \n    def __init__(self, mongo_uri, mongo_db, mongo_collection):\n        self.mongo_uri = mongo_uri\n        self.mongo_db = mongo_db\n        self.mongo_collection = mongo_collection\n    \n    @classmethod\n    def from_crawler(cls, crawler):\n        '''\n        从配置中读取MongoDB连接信息\n        '''\n        return cls(\n            mongo_uri=crawler.settings.get('MONGO_URI'),\n            mongo_db=crawler.settings.get('MONGO_DATABASE', 'scrapy'),\n            mongo_collection=crawler.settings.get('MONGO_COLLECTION', 'items')\n        )\n    \n    def open_spider(self, spider):\n        '''\n        爬虫启动时连接MongoDB\n        '''\n        self.client = pymongo.MongoClient(self.mongo_uri)\n        self.db = self.client[self.mongo_db]\n    \n    def close_spider(self, spider):\n        '''\n        爬虫关闭时断开连接\n        '''\n        self.client.close()\n    \n    def process_item(self, item, spider):\n        '''\n        处理Item，存入MongoDB\n        '''\n        adapter = ItemAdapter(item)\n        # 使用update实现去重，根据URL判断是否已存在\n        self.db[self.mongo_collection].update_one(\n            {'detail_url': adapter.get('detail_url')},\n            {'$set': dict(adapter)},\n            upsert=True\n        )\n        return item\n\n# settings.py中的配置\n'''\nITEM_PIPELINES = {\n    'myproject.pipelines.MongoDBPipeline': 300,\n}\n\nMONGO_URI = 'mongodb://localhost:27017/'\nMONGO_DATABASE = 'dangdang'\nMONGO_COLLECTION = 'books'\n'''\n\nPipeline说明：\n- 使用from_crawler类方法从配置中读取连接信息\n- open_spider在爬虫启动时建立数据库连接\n- close_spider在爬虫关闭时断开连接\n- process_item处理每个Item，使用update_one实现去重存储\n- upsert=True表示如果不存在则插入，存在则更新",
